/**
 * Normalize + Validate Price
 *
 * Primary strategy: Scraper forces amazon.com/USD via locale cookies/headers.
 * The scraper attaches detectedCurrency to each product.
 *
 * This node:
 * 1. Rejects products where detectedCurrency is non-USD (locale enforcement failed)
 * 2. Parses USD prices directly — no conversion math needed
 * 3. Falls back to conversion ONLY as last resort with a warning
 * 4. Does NOT send source_currency — column does not exist in products table
 */

let response = $input.first().json;

if (response && response.body) {
  if (typeof response.body === 'string') {
    try { response = JSON.parse(response.body); } catch (e) { response = {}; }
  } else {
    response = response.body;
  }
}

if (Array.isArray(response)) response = response[0] || {};

const products = Array.isArray(response.products) ? response.products : [];

const niche = $('Split In Batches').item.json;
const category = niche.category || response.category || 'General';
const keyword = niche.keyword || response.keyword || '';

// Emergency-only FX rates (last resort if locale enforcement failed)
const FX_TO_USD = {
  USD: 1,
  PKR: 1 / 280,
  AED: 0.272294,
  GBP: 1.27,
  EUR: 1.08,
  CAD: 0.73,
  AUD: 0.66,
  INR: 0.012,
  SAR: 0.266667
};

function cleanUrl(value) {
  const s = String(value || '').trim();
  const md = s.match(/^\[(https?:\/\/[^\]]+)\]\((https?:\/\/[^)]+)\)$/i);
  if (md) return md[2];
  return s;
}

function detectCurrency(raw) {
  const s = String(raw || '').replace(/\s+/g, ' ').trim();
  if (/\bPKR\b|₨|Rs\.?/i.test(s)) return 'PKR';
  if (/\bAED\b|د\.إ/i.test(s)) return 'AED';
  if (/\bGBP\b/.test(s) || (/£/.test(s) && !/\$/.test(s))) return 'GBP';
  if (/\bEUR\b|€/.test(s)) return 'EUR';
  if (/\bCAD\b|CA\$/.test(s)) return 'CAD';
  if (/\bAUD\b|AU\$/.test(s)) return 'AUD';
  if (/\bINR\b|₹/.test(s)) return 'INR';
  if (/\bSAR\b|ر\.س/.test(s)) return 'SAR';
  if (/\$|\bUSD\b/.test(s)) return 'USD';
  return 'UNKNOWN';
}

function parsePriceToUsdCents(priceText, detectedCurrencyHint) {
  const raw = String(priceText || '').replace(/\s+/g, ' ').trim();
  if (!raw) return null;
  if (/price not available|currently unavailable|check latest price/i.test(raw)) return null;

  const currency = (detectedCurrencyHint && detectedCurrencyHint !== 'UNKNOWN' && detectedCurrencyHint !== 'NONE')
    ? detectedCurrencyHint
    : detectCurrency(raw);

  const numericText = raw.replace(/,/g, '');
  const matches = [...numericText.matchAll(/\d+(?:\.\d+)?/g)]
    .map((m) => Number(m[0]))
    .filter((n) => Number.isFinite(n) && n > 0);

  if (matches.length === 0) return null;

  const amount = Math.min(...matches);

  if (currency !== 'USD') {
    if (currency === 'UNKNOWN') {
      if (amount > 500) {
        return {
          raw, sourceAmount: amount,
          usdAmount: null, priceCents: null,
          error: `Ambiguous price ${amount} with no currency symbol — too large to be USD`
        };
      }
      const usdAmount = amount;
      if (usdAmount < 1 || usdAmount > 999) return null;
      return {
        raw, sourceAmount: amount,
        usdAmount, priceCents: Math.round(usdAmount * 100),
        warning: 'No currency symbol — assumed USD'
      };
    }

    const rate = FX_TO_USD[currency];
    if (!rate) return {
      raw, sourceAmount: amount,
      usdAmount: null, priceCents: null,
      error: `No FX rate for ${currency}`
    };

    const usdAmount = amount * rate;
    if (!Number.isFinite(usdAmount) || usdAmount <= 0) return null;
    if (usdAmount < 1 || usdAmount > 999) return null;

    return {
      raw, sourceAmount: amount,
      usdAmount, priceCents: Math.round(usdAmount * 100),
      warning: `LOCALE_ENFORCEMENT_FAILED: Scraped ${currency} ${amount}, converted to USD ${usdAmount.toFixed(2)}`
    };
  }

  // Happy path: confirmed USD
  if (!Number.isFinite(amount) || amount <= 0) return null;
  if (amount < 1 || amount > 999) return null;

  return {
    raw, sourceAmount: amount,
    usdAmount: amount, priceCents: Math.round(amount * 100)
  };
}

// FIX: rating 0 from scraper means no rating found — store null
// Valid Amazon ratings are 1.0–5.0
function parseRating(value) {
  const raw = String(value || '').trim();
  if (!raw || raw === '0') return null;
  const ratingRaw = parseFloat(raw.replace(/[^0-9.]/g, ''));
  if (!Number.isFinite(ratingRaw) || ratingRaw < 1 || ratingRaw > 5) return null;
  return ratingRaw;
}

function parseReviewCount(value) {
  return parseInt(String(value || '0').replace(/[^0-9]/g, ''), 10) || 0;
}

function makeSlug(title, asin) {
  const slug = String(title || '')
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/(^-|-$)/g, '')
    .slice(0, 100);
  return slug || String(asin || '').toLowerCase();
}

const rows = [];
const rejected = [];
const currencyWarnings = [];

for (const [index, p] of products.entries()) {
  const asin = String(p.asin || '').trim();
  const title = String(p.title || '').trim();
  const affiliateLink = cleanUrl(p.affiliateLink || p.affiliate_url || '');
  const image = cleanUrl(p.image || p.image_url || '');

  if (!asin) { rejected.push({ index, reason: 'missing asin' }); continue; }
  if (!title) { rejected.push({ asin, reason: 'missing title' }); continue; }
  if (!affiliateLink) { rejected.push({ asin, reason: 'missing affiliate link' }); continue; }
  if (!image) { rejected.push({ asin, reason: 'missing image' }); continue; }

  const priceInfo = parsePriceToUsdCents(
    p.price || p.rawPrice || '',
    p.detectedCurrency || null
  );

  if (!priceInfo || priceInfo.priceCents === null) {
    rejected.push({
      asin,
      reason: priceInfo ? priceInfo.error : 'invalid/unparseable price',
      price: p.price || p.rawPrice || '',
      detectedCurrency: p.detectedCurrency || 'unknown'
    });
    continue;
  }

  if (priceInfo.warning) {
    currencyWarnings.push({ asin, warning: priceInfo.warning });
    console.warn(`⚠️ ${asin}: ${priceInfo.warning}`);
  }

  const description =
    (typeof p.reviewSnippet === 'string' && p.reviewSnippet.trim()) ||
    (Array.isArray(p.features) && p.features[0] && String(p.features[0]).trim()) ||
    title;

  // NOTE: source_currency is intentionally excluded — not a column in products table
  rows.push({
    json: {
      id: asin,
      asin,
      slug: makeSlug(title, asin),
      category,
      subcategory: null,
      brand: p.brand && String(p.brand).trim() ? String(p.brand).trim() : null,
      title,
      description,
      keyword,
      price_cents: priceInfo.priceCents,
      currency: 'USD',
      image_url: image,
      affiliate_url: affiliateLink,
      rating: parseRating(p.rating),
      review_count: parseReviewCount(p.reviewCount),
      badge: p.badge && String(p.badge).trim() ? String(p.badge).trim() : null,
      rank: index + 1,
      is_featured: index < 3,
      last_scraped_at: new Date().toISOString()
    }
  });
}

if (rows.length === 0) {
  return [{
    json: {
      _noValidProducts: true,
      keyword, category, rejected, currencyWarnings,
      reason: 'No valid products after validation. Check rejected for currency/price issues.'
    }
  }];
}

if (currencyWarnings.length > 0) {
  console.warn('Currency warnings (locale enforcement may have failed):', JSON.stringify(currencyWarnings));
}

return rows;

const rows = $input
  .all()
  .map((item) => item.json)
  .filter((row) => row && !row._noValidProducts && row.asin);

if (rows.length === 0) {
  return [{ json: { _noValidProducts: true, reason: 'No rows to upsert' } }];
}

return [{ json: { rows, count: rows.length } }];

const item = $input.first().json;
const error = item.error || null;
if (error) {
  const msg = typeof error === 'object' ? JSON.stringify(error) : String(error);
  console.log('Supabase HTTP upsert failed: ' + msg);
}
return [{ json: { ok: !error, error, response: item } }];
